import './App.css';
import { useState } from "react";

function App() {
  const [tasks, setTasks] = useState([
    { id: 1, title: "Study", completed: false },
    { id: 2, title: "Work on project", completed: false }
  ]);

  const [newTask, setNewTask] = useState("");

  const addTask = () => {
  if (!newTask.trim()) return;

  const task = {
    id: Date.now(),
    title: newTask,
    completed: false
  };

  setTasks([...tasks, task]);
  setNewTask("");
};

  return (
    <div>
      <h1>Focus Coach</h1>

      <input
        type="text"
        placeholder="Enter a task"
        value={newTask}
        onChange={(e) => setNewTask(e.target.value)}
      />

     <button onClick={addTask}>
  Add Task
</button>

      <ul>
        {tasks.map(task => (
          <li key={task.id}>{task.title}</li>
        ))}
      </ul>
    </div>
  );
}

export default App;
